example.code:
// Set Agent to log warnings and errors only
api.SetLoggingLevel(LogLevel.WARN);

// Log a debug message (will only appear if level is DEBUG or TRACE)
api.LogMessageOnAgent(LogLevel.DEBUG, "Test started");

// Get widget geometry
var geometry = api.GetObjectFieldValue<FGeometry>("//*[@name='MyButton']/@CachedGeometry");
Console.WriteLine($"Widget at {geometry.AbsolutePosition}, size {geometry.AbsoluteSize}");

// Game has a method: void ProcessTarget(GameObject target)
// Pass an object reference using HPathObject
api.CallMethod(
    "//*[@name='GameManager']/fn:component('TargetSystem')",
    "ProcessTarget",
    new object[] { new HPathObject("//*[@name='Enemy']") }
);

member.example:
// Create ObjectRef from an HPath
var sliderRef = api.CreateObjectRef("//*[@name='Slider']/fn:component('UnityEngine.UI.Slider')");

// Use directly with API methods
var value = api.GetObjectFieldValue<float>(sliderRef, "value");

// Use within HPath queries
var value = api.GetObjectFieldValue<float>($"fn:objectref('{sliderRef}')/@value");

// Clean up when done
api.RemoveObjectRef(sliderRef);
